class Buffer {
    char* data_; size_t size_;
public:
    explicit Buffer(size_t size) : data_(new char[size]()), size_(size) {}
    ~Buffer() { delete[] data_; }

    Buffer(const Buffer& o) : data_(new char[o.size_]), size_(o.size_) {
        std::memcpy(data_, o.data_, size_);
    }
    Buffer(Buffer&& o) noexcept : data_(o.data_), size_(o.size_) {
        o.data_ = nullptr; o.size_ = 0;
    }
    Buffer& operator=(Buffer o) { // copy-and-swap
        std::swap(data_, o.data_); std::swap(size_, o.size_);
        return *this;
    }
    size_t size() const { return size_; }
};

