#include <mutex>
#include <condition_variable>
#include <queue>

template<typename T>
class Channel {
    std::queue<T> q_;
    std::mutex mtx_;
    std::condition_variable cv_;
public:
    void send(T val) {
        std::lock_guard lk(mtx_);
        q_.push(std::move(val));
        cv_.notify_one();
    }
    T recv() {
        std::unique_lock lk(mtx_);
        cv_.wait(lk, [this]{ return !q_.empty(); });
        T val = std::move(q_.front()); q_.pop();
        return val;
    }
};

int main() {
    Channel<int> ch;
    std::jthread producer([&](std::stop_token) {
        for (int i = 0; i < 5; i++) ch.send(i);
    });
    for (int i = 0; i < 5; i++)
        std::cout << ch.recv() << " ";
}

