template<typename T>
class Sorter {
    using Strategy = std::function<bool(const T&, const T&)>;
    Strategy strategy_;
public:
    Sorter(Strategy s = std::less<T>{}) : strategy_(std::move(s)) {}
    void sort(std::vector<T>& data) {
        std::sort(data.begin(), data.end(), strategy_);
    }
    void setStrategy(Strategy s) { strategy_ = std::move(s); }
};

int main() {
    std::vector<int> data = {5, 2, 8, 1, 9};
    Sorter<int> sorter;
    sorter.sort(data); // ascending
    sorter.setStrategy(std::greater<int>{});
    sorter.sort(data); // descending
    for (int n : data) std::cout << n << " "; // 9 8 5 2 1
}
